#include <stdio.h>

int main() {
 int num = 42;
 float pi = 3.14159;
 char grade = 'A';
 char name[] = "university";

 // Integer output
 printf("Integer: %d\n", num);

 // Float with default and custom precision
 printf("Float: %f\n", pi);
 printf("Pi: %.2f\n", pi);

 // Character and string
 printf("Grade: %c\n", grade);
 printf("University: %s\n", name);

 // Multiple values
 printf("Number: %d, Pi: %.3f\n", num, pi);

 return 0;
}

#include <stdio.h>

int main() {
 int x = 42;
 float y = 3.14159;
 char s[] = "Programming";

 // Field width examples
 printf("|%5d|\n", x); // | 42| (right-aligned)
 printf("|%-5d|\n", x); // |42 | (left-aligned)
 printf("|%05d|\n", x); // |00042| (zero-padded)

 // Precision examples
 printf("%.2f\n", y); // 3.14 (2 decimals)
 printf("%.3f\n", y); // 3.142 (3 decimals)
 printf("%.5s\n", s); // Progr (first 5 chars)

 // Combined width and precision
 printf("%10.2f\n", y); // | 3.14| (width 10, 2 decimals)

 return 0;
}

#include <stdio.h>

int main() {
 // Newline and tab
 printf("Name: John\n"); // New line after
 printf("Age: 20\t"); // Tab after
 printf("Marks: 95\n"); // New line after

 // Other escape sequences
 printf("Path: C:\\Users\\John\n"); // Backslash
 printf("Quote: \"Hello\"\n"); // Double quote
 printf("Percent: 100%%\n"); // Percent sign

 // Carriage return (overwrites)
 printf("Loading: 0\rLoading: 100%%"); // Rewrites line

 return 0;
}

#include <stdio.h>

int main() {
 // printf returns number of characters printed
 int count;

 count = printf("Hello"); // Returns 5
 printf("\nCharacters printed: %d\n", count);

 count = printf("CSE\n"); // Returns 8 (7 letters + 1 newline)
 printf("Characters printed: %d\n", count);

 // Using return value for validation
 int result = printf("Value: %d", 100);
 if (result < 0) {
 printf("\nOutput error occurred");
 } else {
 printf("\nSuccessfully printed %d chars\n", result);
 }

 return 0;
}
